import xml.etree.ElementTree as ET
tree = ET.parse('test_multiline.svg')
ns = {'svg': 'http://www.w3.org/2000/svg'}
texts = tree.findall('svg:text', ns)
if len(texts) >= 2:
    lines = [t.text for t in texts if t.text]
    assert 'Line1' in lines and 'Line2' in lines, f"Lines not found: {lines}"
else:
    assert len(texts) == 1 and texts[0].text and '\n' in texts[0].text, "Expected newline in text"
